import React, { useState } from 'react';

const campos = [
  'Nome da Estação',
  'Código Anatel',
  'Endereço',
  'Município',
  'UF',
  'Latitude',
  'Longitude',
  'Tipo de Estação',
  'Status',
  'Data de Ativação',
  'Responsável Técnico',
  'Contato',
  'Observações'
];

export default function EstacoesInfra() {
  const [valores, setValores] = useState(Array(campos.length).fill(''));

  const handleChange = (idx, value) => {
    const novo = [...valores];
    novo[idx] = value;
    setValores(novo);
  };

  const handleSubmit = (e) => {
    e.preventDefault();
    // Aqui você pode salvar os dados ou enviar para API
    alert('Dados salvos!');
  };

  return (
    <form onSubmit={handleSubmit} style={{maxWidth: 400, margin: '32px auto', background: '#222', padding: 24, borderRadius: 12, color: '#fff'}}>
      <h2 style={{marginBottom: 24}}>Cadastro de Estação</h2>
      {campos.map((campo, idx) => (
        <div key={campo} style={{marginBottom: 16}}>
          <label style={{display: 'block', marginBottom: 4}}>{campo}</label>
          <input
            type="text"
            value={valores[idx]}
            onChange={e => handleChange(idx, e.target.value)}
            style={{width: '100%', padding: 8, borderRadius: 4, border: '1px solid #444', background: '#111', color: '#fff'}}
          />
        </div>
      ))}
      <button type="submit" style={{marginTop: 16, padding: '8px 24px', borderRadius: 6, background: '#1976d2', color: '#fff', border: 'none', fontWeight: 600}}>Salvar</button>
    </form>
  );
}
